const FW25_MAP = {202601:202501,202602:202502,202603:202503,202604:202504,202605:202505,202606:202506,202607:202507,202608:202508,202609:202509,202610:202510,202611:202511,202612:202512};

const fmt$ = n => n==null?"—":"$"+Math.abs(n).toLocaleString("en-US",{minimumFractionDigits:2,maximumFractionDigits:2});
const fmtD = n => n==null?"—":(n>=0?"+":"-")+"$"+Math.abs(n).toLocaleString("en-US",{minimumFractionDigits:2,maximumFractionDigits:2});
const fmtP = n => n==null?"—":(n>=0?"+":"")+n.toFixed(1)+"%";
const fmtST = n => n==null?"—":n.toFixed(1)+"%";
const fmtU = n => n==null?"—":Math.round(n).toLocaleString("en-US");
const clr = n => n==null?"#7ec8e3":n>=0?"#4ade80":"#f87171";
const stClr = n => n==null?"#7ec8e3":n>=80?"#4ade80":n>=60?"#f5a623":"#f87171";

function MultiSelect({label, options, selected, onChange, fmtOpt}) {
  const [open, setOpen] = useState(false);
  const all = selected.length===options.length;
  const toggle = v => selected.includes(v)?onChange(selected.filter(x=>x!==v)):onChange([...selected,v]);
  return (
    <div style={{position:"relative",display:"inline-block",minWidth:155}}>
      <button onClick={()=>setOpen(!open)} style={{background:"#0d1b2a",border:"1px solid #1e3a5a",color:"#a0c4dc",padding:"7px 12px",borderRadius:6,cursor:"pointer",fontSize:11,width:"100%",textAlign:"left",display:"flex",justifyContent:"space-between",alignItems:"center",fontFamily:"'DM Mono',monospace"}}>
        <span>{label}: {all?"All":selected.length===0?"None":selected.length+" sel."}</span>
        <span style={{marginLeft:8,opacity:0.5}}>{open?"▲":"▼"}</span>
      </button>
      {open&&(
        <div style={{position:"absolute",zIndex:9999,top:"105%",left:0,background:"#0a1628",border:"1px solid #1e3a5a",borderRadius:7,minWidth:210,maxHeight:280,overflowY:"auto",boxShadow:"0 12px 40px #0008"}}>
          <div onClick={()=>all?onChange([]):onChange([...options])} style={{padding:"8px 14px",cursor:"pointer",borderBottom:"1px solid #1e3a5a",color:"#7ec8e3",fontSize:11,fontWeight:600,fontFamily:"'DM Mono',monospace"}}>{all?"Deselect All":"Select All"}</div>
          {options.map(o=>(
            <div key={o} onClick={()=>toggle(o)} style={{padding:"6px 14px",cursor:"pointer",fontSize:11,color:selected.includes(o)?"#7ec8e3":"#6688aa",background:selected.includes(o)?"#111e30":"transparent",display:"flex",alignItems:"center",gap:8,fontFamily:"'DM Mono',monospace"}}>
              <span style={{width:11,height:11,borderRadius:3,border:"1px solid #3a5a7a",background:selected.includes(o)?"#3a8fd4":"transparent",display:"inline-block",flexShrink:0}}/>
              {fmtOpt?fmtOpt(o):o}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

function KPI({label,value,delta,pct,stVal}) {
  const c = stVal!=null ? stClr(stVal) : (delta==null?"#7ec8e3":delta>=0?"#4ade80":"#f87171");
  return (
    <div style={{background:"linear-gradient(135deg,#0f1f35 60%,#0a2040 100%)",border:"1px solid #1e3a5a",borderRadius:10,padding:"16px 18px",flex:1,minWidth:130}}>
      <div style={{fontSize:9,color:"#3a6a8a",fontFamily:"'DM Mono',monospace",letterSpacing:1.5,textTransform:"uppercase",marginBottom:6}}>{label}</div>
      <div style={{fontSize:20,fontWeight:700,color: stVal!=null?c:"#d8eefa",fontFamily:"'DM Mono',monospace"}}>{value}</div>
      {delta!=null&&<div style={{marginTop:5,display:"flex",gap:7,alignItems:"center"}}>
        <span style={{fontSize:12,color:c,fontFamily:"'DM Mono',monospace"}}>{fmtD(delta)}</span>
        <span style={{fontSize:10,color:c,background:c+"22",borderRadius:4,padding:"2px 6px",fontFamily:"'DM Mono',monospace"}}>{fmtP(pct)}</span>
      </div>}
    </div>
  );
}

function STBar({val}) {
  if(val==null) return <span style={{color:"#3a5a7a",fontFamily:"'DM Mono',monospace",fontSize:11}}>—</span>;
  const capped = Math.min(val,100);
  const c = stClr(val);
  return (
    <div style={{display:"flex",alignItems:"center",gap:6,justifyContent:"flex-end"}}>
      <div style={{width:48,height:6,background:"#0d1b2a",borderRadius:3,overflow:"hidden"}}>
        <div style={{width:capped+"%",height:"100%",background:c,borderRadius:3}}/>
      </div>
      <span style={{color:c,fontFamily:"'DM Mono',monospace",fontSize:11,minWidth:42,textAlign:"right"}}>{fmtST(val)}</span>
    </div>
  );
}


function Sparkline({prod}) {
  const vals = SPARK_DATA[prod] || [];
  if(!vals.length) return <span style={{color:"#2a4a6a",fontSize:10}}>—</span>;
  const max = Math.max(...vals, 1);
  const w = 6, gap = 2, h = 28;
  const total = vals.length*(w+gap)-gap;
  return (
    <svg width={total} height={h} style={{display:"block"}}>
      {vals.map((v,i)=>{
        const barH = Math.max(2, Math.round((v/max)*h));
        const c = v===Math.max(...vals)?"#4ade80":v===Math.min(...vals)?"#f87171":"#3a8fd4";
        return <rect key={i} x={i*(w+gap)} y={h-barH} width={w} height={barH} fill={c} rx={1}/>;
      })}
    </svg>
  );
}


function TopBottom3({rows, nameKey, valueKey, label, fmt: fmtFn}) {
  if(!rows||rows.length<2) return null;
  const sorted = [...rows].sort((a,b)=>(b[valueKey]||0)-(a[valueKey]||0));
  const top3 = sorted.slice(0,3);
  const bot3 = sorted.slice(-3).reverse();
  return (
    <div style={{display:"flex",gap:12,marginBottom:20,flexWrap:"wrap"}}>
      <div style={{background:"#071510",border:"1px solid #1a3a2a",borderRadius:8,padding:"12px 16px",flex:1,minWidth:260}}>
        <div style={{fontSize:9,color:"#4ade80",letterSpacing:1.5,textTransform:"uppercase",marginBottom:8}}>Top 3 · {label}</div>
        {top3.map((r,i)=>(
          <div key={i} style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:5}}>
            <span style={{fontSize:10,color:"#a0c4dc",fontFamily:"DM Mono,monospace"}}>{r[nameKey]}</span>
            <span style={{fontSize:11,color:"#4ade80",fontFamily:"DM Mono,monospace",fontWeight:600}}>{fmtFn(r[valueKey])}</span>
          </div>
        ))}
      </div>
      <div style={{background:"#150709",border:"1px solid #3a1a1a",borderRadius:8,padding:"12px 16px",flex:1,minWidth:260}}>
        <div style={{fontSize:9,color:"#f87171",letterSpacing:1.5,textTransform:"uppercase",marginBottom:8}}>Bottom 3 · {label}</div>
        {bot3.map((r,i)=>(
          <div key={i} style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:5}}>
            <span style={{fontSize:10,color:"#a0c4dc",fontFamily:"DM Mono,monospace"}}>{r[nameKey]}</span>
            <span style={{fontSize:11,color:"#f87171",fontFamily:"DM Mono,monospace",fontWeight:600}}>{fmtFn(r[valueKey])}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

function THead({cols,sort,onSort}) {
  return (
    <thead>
      <tr style={{background:"#0a1628"}}>
        {cols.map(c=>(
          <th key={c.key} onClick={()=>onSort&&onSort(c.key)} style={{padding:"10px 14px",textAlign:c.num?"right":"left",fontSize:9,color:sort===c.key?"#7ec8e3":"#3a6a8a",fontFamily:"'DM Mono',monospace",letterSpacing:1.2,textTransform:"uppercase",cursor:onSort?"pointer":"default",background:sort===c.key?"#0f1f35":"transparent",borderBottom:"1px solid #1e3a5a",whiteSpace:"nowrap"}}>
            {c.label}{sort===c.key?" ▼":""}
          </th>
        ))}
      </tr>
    </thead>
  );
}

